execute_battle_turn.python_script:
import json

target = int(input_data["target_move_index"])
current = int(input_data["current_move_index"])
start = bool(input_data.get("start_on_main", True))
main_cursor = input_data.get("main_cursor", "FIGHT")

buttons = []
if start:
    if main_cursor == "FIGHT":
        pass
    elif main_cursor == "PKMN":
        buttons.append("Left")
    elif main_cursor == "ITEM":
        buttons.append("Up")
    elif main_cursor == "RUN":
        buttons.extend(["Up", "Left"])
    buttons.append("A")
    buttons.append("sleep 500")

diff = target - current
if diff > 0:
    if diff == 3:
        buttons.append("Up")
    else:
        buttons.extend(["Down"] * diff)
elif diff < 0:
    if diff == -3:
        buttons.append("Down")
    else:
        buttons.extend(["Up"] * abs(diff))
buttons.append("A")

print(json.dumps(buttons))

switch_pokemon_in_battle.python_script:
import json

def generate_moves(input_data):
    start_on_main = input_data.get('start_on_main', True)
    current_index = int(input_data['current_index'])
    target_index = int(input_data['target_index'])

    presses = []
    if start_on_main:
        presses.extend(['Right', 'sleep 300', 'A', 'sleep 1500'])

    diff = target_index - current_index

    if diff > 0:
        for _ in range(diff):
            presses.extend(['Down', 'sleep 300'])
    elif diff < 0:
        for _ in range(abs(diff)):
            presses.extend(['Up', 'sleep 300'])

    # Press A to select the Pokemon, then A again to select "SWITCH" in the sub-menu
    presses.extend(['A', 'sleep 1000', 'A', 'sleep 1000'])
    print(json.dumps(presses))

generate_moves(input_data)
